const data = Array.isArray($json.data) ? $json.data : (Array.isArray($json) ? $json : [$json]);
const stock = (data[0] && data[0].symbol) || "UNKNOWN";

return [{
  json: {
    stock: stock,
    cashflow_quarterly: data
  }
}];

// ── Guard: skip the loop's done-signal item ──────────────────────────────────

function num(v) {
  if (v === null || v === undefined || v === '' || v === 'None') return null;
  const n = Number(String(v).replace(/[,$%]/g, ''));
  return isFinite(n) ? n : null;
}
function safeDiv(a, b) {
  return (a !== null && b !== null && b !== 0) ? a / b : null;
}

const stock    = $json.stock;
const profile  = $json.profile_data  || {};
const kmTTM    = Array.isArray($json.key_metrics_ttm)
                   ? ($json.key_metrics_ttm[0] || {})
                   : ($json.key_metrics_ttm || {});

// Use quarterly arrays; fall back gracefully when period/limit not yet added
const incQ  = Array.isArray($json.income_quarterly)   ? $json.income_quarterly   : [];
const incA  = Array.isArray($json.income_annual)       ? $json.income_annual      : [];
const balQ  = Array.isArray($json.balance_quarterly)   ? $json.balance_quarterly  : [];
const balA  = Array.isArray($json.balance_annual)      ? $json.balance_annual     : [];
const cfQ   = Array.isArray($json.cashflow_quarterly)  ? $json.cashflow_quarterly : [];
const cfA   = Array.isArray($json.cashflow_annual)     ? $json.cashflow_annual    : [];

const current_price = num($json.current_price) || num(profile.price);
const sector        = profile.sector || '';

// For balance: prefer quarterly (debt/cash tracking), fall back to annual
const balSource = balQ.length ? balQ : balA;

// ── Quarterly arrays (last 4Q) ───────────────────────────────────────────────
const revenue_last_4q = incQ.slice(0, 4).map(q => num(q.revenue));

const net_income_last_4q = incQ.slice(0, 4).map(q => num(q.netIncome));

const gross_margin_last_4q = incQ.slice(0, 4).map(q => {
  const rev = num(q.revenue), gp = num(q.grossProfit);
  return (rev && gp !== null && rev > 0) ? Number(((gp / rev) * 100).toFixed(2)) : null;
});

const total_debt_last_4q = balSource.slice(0, 4).map(q => {
  const t = num(q.totalDebt);
  if (t !== null && t > 0) return t;
  const s = num(q.shortTermDebt) || 0, l = num(q.longTermDebt) || 0;
  return (s + l) > 0 ? (s + l) : null;
});

const cash_last_4q = balSource.slice(0, 4).map(q => num(q.cashAndCashEquivalents));

// ── Latest balance ───────────────────────────────────────────────────────────
const latestBal  = balSource[0] || {};
const debt_latest = num(latestBal.totalDebt) ||
  ((num(latestBal.shortTermDebt) || 0) + (num(latestBal.longTermDebt) || 0)) || null;
const cash_latest = num(latestBal.cashAndCashEquivalents);

let net_debt_latest = null, net_cash_flag = null;
if (debt_latest !== null && cash_latest !== null) {
  net_debt_latest = debt_latest - cash_latest;
  net_cash_flag   = net_debt_latest < 0;
}

// ── TTM: Revenue ─────────────────────────────────────────────────────────────
// Prefer key_metrics_ttm; fall back to summing quarters
let revenue_ttm = null;
if (num(kmTTM.revenuePerShareTTM) !== null && num(kmTTM.weightedAverageShsOutDilTTM) !== null) {
  revenue_ttm = num(kmTTM.revenuePerShareTTM) * num(kmTTM.weightedAverageShsOutDilTTM);
} else {
  const r4 = revenue_last_4q.filter(v => v !== null);
  if (r4.length > 0) revenue_ttm = r4.reduce((a, b) => a + b, 0);
}

// ── Revenue growth YoY (needs 8 quarters) ────────────────────────────────────
let revenue_growth_yoy = null;
const rev8      = incQ.slice(0, 8).map(q => num(q.revenue));
const curr_ttm  = rev8.slice(0, 4).every(v => v !== null) ? rev8.slice(0, 4).reduce((a, b) => a + b, 0) : null;
const prev_ttm  = rev8.slice(4, 8).every(v => v !== null) ? rev8.slice(4, 8).reduce((a, b) => a + b, 0) : null;
if (curr_ttm !== null && prev_ttm !== null && prev_ttm !== 0) {
  revenue_growth_yoy = Number((((curr_ttm - prev_ttm) / prev_ttm) * 100).toFixed(2));
}

// ── Net income TTM ───────────────────────────────────────────────────────────
const net_income_ttm = (net_income_last_4q.length === 4 && net_income_last_4q.every(v => v !== null))
  ? net_income_last_4q.reduce((a, b) => a + b, 0)
  : null;

// ── Gross margin TTM ─────────────────────────────────────────────────────────
let gross_margin_ttm = null;
if (num(kmTTM.grossProfitMarginTTM) !== null) {
  // FMP returns this as decimal (0.36 = 36%)
  gross_margin_ttm = Number((num(kmTTM.grossProfitMarginTTM) * 100).toFixed(2));
} else if (curr_ttm !== null && curr_ttm > 0) {
  const gp4 = incQ.slice(0, 4).map(q => num(q.grossProfit));
  if (gp4.every(v => v !== null)) {
    gross_margin_ttm = Number(((gp4.reduce((a, b) => a + b, 0) / curr_ttm) * 100).toFixed(2));
  }
}

// ── Operating margin TTM ─────────────────────────────────────────────────────
let operating_margin_ttm = null;
if (num(kmTTM.operatingIncomeRatioTTM) !== null) {
  operating_margin_ttm = Number((num(kmTTM.operatingIncomeRatioTTM) * 100).toFixed(2));
} else if (curr_ttm !== null && curr_ttm > 0) {
  const oi4 = incQ.slice(0, 4).map(q => num(q.operatingIncome));
  if (oi4.every(v => v !== null)) {
    operating_margin_ttm = Number(((oi4.reduce((a, b) => a + b, 0) / curr_ttm) * 100).toFixed(2));
  }
}

// ── FCF TTM ──────────────────────────────────────────────────────────────────
let fcf_ttm = null;
if (cfQ.length >= 4) {
  // Sum last 4 quarters: FMP provides freeCashFlow directly
  const fcf4 = cfQ.slice(0, 4).map(r => num(r.freeCashFlow));
  if (fcf4.every(v => v !== null)) {
    fcf_ttm = fcf4.reduce((a, b) => a + b, 0);
  } else {
    // Compute from OCF + capex (capex is negative in FMP)
    const ocf4  = cfQ.slice(0, 4).map(r => num(r.operatingCashFlow));
    const cap4  = cfQ.slice(0, 4).map(r => num(r.capitalExpenditure));
    if (ocf4.every(v => v !== null) && cap4.every(v => v !== null)) {
      fcf_ttm = ocf4.reduce((a, b) => a + b, 0) + cap4.reduce((a, b) => a + b, 0);
    }
  }
} else if (cfQ.length > 0) {
  // Only 1 quarter available — use what we have as best estimate
  const r = cfQ[0];
  fcf_ttm = num(r.freeCashFlow) ??
            ((num(r.operatingCashFlow) !== null && num(r.capitalExpenditure) !== null)
              ? num(r.operatingCashFlow) + num(r.capitalExpenditure)
              : null);
} else if (cfA.length) {
  const r = cfA[0];
  fcf_ttm = num(r.freeCashFlow) ??
            ((num(r.operatingCashFlow) !== null && num(r.capitalExpenditure) !== null)
              ? num(r.operatingCashFlow) + num(r.capitalExpenditure)
              : null);
}

// ── Total debt TTM ───────────────────────────────────────────────────────────
const total_debt_ttm = debt_latest;

// ── EPS, BVPS, Shares ────────────────────────────────────────────────────────
// Prefer key_metrics_ttm; fall back to latest quarterly income
const eps_current = num(kmTTM.netIncomePerShareTTM)
  || (incQ.length ? num(incQ[0].epsDiluted) : null);

const bvps_current = num(kmTTM.bookValuePerShareTTM)
  || (() => {
    const eq = num(latestBal.totalStockholdersEquity);
    const sh = incQ.length ? num(incQ[0].weightedAverageShsOutDil) : null;
    return (eq !== null && sh !== null && sh > 0) ? Number((eq / sh).toFixed(2)) : null;
  })();

const shares_outstanding = num(kmTTM.weightedAverageShsOutDilTTM)
  || (incQ.length ? num(incQ[0].weightedAverageShsOutDil) : null);

// ── Piotroski F-Score (needs 2 annual years for meaningful score) ─────────────
// Uses annual income + annual balance + annual cashflow
const y0_inc = incA[0] || null, y1_inc = incA[1] || null;
const y0_bal = balA[0] || null, y1_bal = balA[1] || null;
const y0_cf  = cfA[0]  || null, y1_cf  = cfA[1]  || null;

const NI0  = y0_inc ? num(y0_inc.netIncome)                : null;
const NI1  = y1_inc ? num(y1_inc.netIncome)                : null;
const TA0  = y0_bal ? num(y0_bal.totalAssets)              : null;
const TA1  = y1_bal ? num(y1_bal.totalAssets)              : null;
const CFO0 = y0_cf  ? num(y0_cf.operatingCashFlow)         : null;
const CFO1 = y1_cf  ? num(y1_cf.operatingCashFlow)         : null;
const LTD0 = y0_bal ? num(y0_bal.longTermDebt)             : null;
const LTD1 = y1_bal ? num(y1_bal.longTermDebt)             : null;
const CA0  = y0_bal ? num(y0_bal.totalCurrentAssets)       : null;
const CA1  = y1_bal ? num(y1_bal.totalCurrentAssets)       : null;
const CL0  = y0_bal ? num(y0_bal.totalCurrentLiabilities)  : null;
const CL1  = y1_bal ? num(y1_bal.totalCurrentLiabilities)  : null;
const REV0 = y0_inc ? num(y0_inc.revenue)                  : null;
const REV1 = y1_inc ? num(y1_inc.revenue)                  : null;
const GP0  = y0_inc ? num(y0_inc.grossProfit)              : null;
const GP1  = y1_inc ? num(y1_inc.grossProfit)              : null;
const SH0  = y0_inc ? num(y0_inc.weightedAverageShsOutDil) : null;
const SH1  = y1_inc ? num(y1_inc.weightedAverageShsOutDil) : null;

// Add this before the F-score block:
const hasY1 = !!(y1_inc && y1_bal && y1_cf);

// Then wrap year-over-year comparisons:
let f_score = 0;
if (NI0 !== null && NI0 > 0)                                                         f_score++; // F1
if (CFO0 !== null && CFO0 > 0)                                                        f_score++; // F2
if (hasY1 && safeDiv(NI0,TA0) !== null && safeDiv(NI0,TA0) > safeDiv(NI1,TA1))      f_score++; // F3
if (CFO0 !== null && NI0 !== null && CFO0 > NI0)                                      f_score++; // F4
if (hasY1 && LTD0 !== null && LTD1 !== null && LTD0 < LTD1)                          f_score++; // F5
if (hasY1 && safeDiv(CA0,CL0) !== null && safeDiv(CA0,CL0) > safeDiv(CA1,CL1))      f_score++; // F6
if (hasY1 && SH0 !== null && SH1 !== null && SH0 <= SH1)                             f_score++; // F7
if (hasY1 && safeDiv(GP0,REV0) !== null && safeDiv(GP0,REV0) > safeDiv(GP1,REV1))   f_score++; // F8
if (hasY1 && safeDiv(REV0,TA0) !== null && safeDiv(REV0,TA0) > safeDiv(REV1,TA1))   f_score++; // F9


const f_score_data_ok = !!(y0_inc && y1_inc && y0_bal && y1_bal && y0_cf && y1_cf);

// ── Graham Number ─────────────────────────────────────────────────────────────
let graham_number = null;
if (eps_current > 0 && bvps_current > 0) {
  graham_number = Number(Math.sqrt(22.5 * eps_current * bvps_current).toFixed(2));
}

// ── DCF Anchor ────────────────────────────────────────────────────────────────
const disc_rate_map = {
  'Technology': 0.10, 'Financial Services': 0.09, 'Utilities': 0.08,
  'Consumer Defensive': 0.09, 'Consumer Cyclical': 0.11,
  'Healthcare': 0.10, 'Industrials': 0.10, 'Basic Materials': 0.10,
  'Energy': 0.11, 'Communication Services': 0.10, 'Real Estate': 0.09
};
const disc_rate      = disc_rate_map[sector] || 0.10;
const terminal_growth = 0.03;
let dcf_anchor = null;
if (fcf_ttm !== null && fcf_ttm > 0) {
  const fcf_growth = (curr_ttm !== null && prev_ttm !== null && prev_ttm > 0)
    ? Math.min((curr_ttm - prev_ttm) / prev_ttm, 0.30)
    : 0.08;
  const fcf5 = fcf_ttm * Math.pow(1 + fcf_growth, 5);
const dcf_ev = fcf5 / (disc_rate - terminal_growth);
dcf_anchor = shares_outstanding > 0
  ? Number((dcf_ev / shares_outstanding).toFixed(2))
  : null;}

// ── Sector P/E ────────────────────────────────────────────────────────────────
const sectorPE = {
  'Technology': 25, 'Financial Services': 12, 'Utilities': 15,
  'Consumer Defensive': 19, 'Consumer Cyclical': 22,
  'Healthcare': 20, 'Industrials': 18, 'Basic Materials': 16,
  'Energy': 14, 'Communication Services': 21, 'Real Estate': 17
};
const sector_median_pe = sectorPE[sector] || 18;

// ── Output ────────────────────────────────────────────────────────────────────
return {
  json: {
    stock,
    eps_current,
    bvps_current,
    shares_outstanding,
    revenue_ttm,
    total_debt_ttm,
    gross_margin_ttm,
    operating_margin_ttm,
    fcf_ttm,
    net_income_ttm,
    revenue_last_4q:      revenue_last_4q.some(v => v !== null)      ? revenue_last_4q      : [],
    net_income_last_4q:   net_income_last_4q.some(v => v !== null)   ? net_income_last_4q   : [],
    gross_margin_last_4q: gross_margin_last_4q.some(v => v !== null) ? gross_margin_last_4q : null,
    total_debt_last_4q:   total_debt_last_4q.some(v => v !== null)   ? total_debt_last_4q   : null,
    cash_last_4q:         cash_last_4q.some(v => v !== null)         ? cash_last_4q         : null,
    revenue_growth_yoy,
    current_price,
    net_debt_latest,
    cash_latest,
    debt_latest,
    net_cash_flag,
    f_score,
    f_score_data_ok,
    sector,
    graham_number,
    dcf_anchor,
    sector_median_pe,
    cache: {
      status: 'fresh',
      source: 'fmp',
      last_updated: new Date().toISOString()
    }
  }
};

const inJson = $json || {};
const q = Array.isArray(inJson) ? inJson[0] : inJson;
const stock = q.symbol || $input.item.json.stock || "UNKNOWN";

return [{
  json: {
    stock: stock,
    current_price: q.price ? Number(q.price) : null
  }
}];

let saXml = null;
let stock = "";

try {
  stock =
    $json.stock ??
    $json.ticker ??
    ($node["loop_over_tickers"]?.json?.stock ?? "");

  if (!$json.errorMessage && !$json.error) {

    saXml =                    // ← no "let" here, assigns to outer variable
      (typeof $json.sa_xml       === "string" && $json.sa_xml.trim())       ? $json.sa_xml.trim() :
      (typeof $json.body         === "string" && $json.body.trim())         ? $json.body.trim() :
      (typeof $json.data         === "string" && $json.data.trim())         ? $json.data.trim() :
      (typeof $json.responseBody === "string" && $json.responseBody.trim()) ? $json.responseBody.trim() :
      (typeof $json.text         === "string" && $json.text.trim())         ? $json.text.trim() :
      null;

    if (!saXml && $binary) {
      const key = Object.keys($binary)[0];
      const b64 = key && $binary[key]?.data ? $binary[key].data : null;
      if (b64) {
        const decoded = Buffer.from(b64, "base64").toString("utf8").trim();
        if (decoded) saXml = decoded;
      }
    }
  }
} catch(e) {
  saXml = null;
}

return [{
  json: {
    stock,
    sa_xml: saXml,
    sa_ok:  !!saXml
  }
}];

return [{
  json: {
    stock:                   $json.stock ?? "",
    seekingAlphaWindowHours: 96,
    seekingAlphaCount:       0,
    seekingAlphaHasRecent:   false,
    seekingAlphaRecentCount: 0,
    seekingAlphaNews:        [],
    seekingAlphaNewsText:    null,
    seekingAlphaLatestDate:  null,
    seekingAlphaError:       $json.sa_error ?? "No XML to parse"
  }
}];

// ---- CONFIG ----
const windowHours  = 96;
const fallbackCount = 3;
const now    = Date.now();
const cutoff = now - windowHours * 3600 * 1000;

// ---- GET INPUT ----
const input = $input.first().json;

const stock = input?.stock ?? input?.ticker ?? "";

// ---- INPUT PATH ----
const items =
  input?.rss?.channel?.item ??
  input?.channel?.item ??
  input?.item ??
  [];

const arr = Array.isArray(items) ? items : [items];

// ---- HELPERS ----
function cleanHtml(s) {
  if (!s) return "";
  return String(s)
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<\/?[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function toMillis(dateStr) {
  const t = Date.parse(dateStr);
  return Number.isFinite(t) ? t : NaN;
}

function getLink(i) {
  const l = i.link;
  if (!l) return "";
  if (typeof l === "string") return l;
  if (Array.isArray(l)) return getLink({ link: l[0] });
  return l["#text"] || l.href || l?.$?.href || "";
}

// ---- PARSE ALL ITEMS ----
const parsedAll = arr
  .map(i => {
    const publishedAt = i.pubDate || i.published || i.date || "";
    const t = toMillis(publishedAt);
    return {
      source:        "SeekingAlpha_RSS",
      title:         cleanHtml(i.title),
      link:          getLink(i),
      publishedAt,
      publishedAtMs: t,
      snippet:       cleanHtml(i.description || i.summary || i["content:encoded"])
    };
  })
  .filter(n => n.title && n.link && Number.isFinite(n.publishedAtMs))
  .sort((a, b) => b.publishedAtMs - a.publishedAtMs);

// ---- DEDUPE ----
const seen = new Set();
const dedupedAll = [];
for (const n of parsedAll) {
  if (seen.has(n.link)) continue;
  seen.add(n.link);
  dedupedAll.push(n);
}

// ---- RECENT WINDOW ----
const recent = dedupedAll.filter(n => n.publishedAtMs >= cutoff);

// ---- FINAL SELECTION ----
const selected  = recent.length > 0 ? recent : dedupedAll.slice(0, fallbackCount);
const hasRecent = recent.length > 0;

// ---- CREATE COMPACT TEXT ----
const seekingAlphaNewsText = selected.length > 0
  ? selected.map(n => {
      const shortSnippet = n.snippet.length > 240
        ? n.snippet.slice(0, 240) + "…"
        : n.snippet;
      return `- ${n.publishedAt} | ${n.title}\n  ${n.link}\n  Snippet: ${shortSnippet}`;
    }).join("\n\n")
  : null;

return [{
  json: {
    stock,
    seekingAlphaWindowHours: windowHours,
    seekingAlphaHasRecent:   hasRecent,
    seekingAlphaRecentCount: recent.length,
    seekingAlphaCount:       selected.length,
    seekingAlphaNews:        selected.map(({ publishedAtMs, ...rest }) => rest),
    seekingAlphaNewsText,
    seekingAlphaLatestDate:  dedupedAll[0]?.publishedAt ?? null
  }
}];

let parsed = $json;
const t = $json?.output?.[0]?.content?.[0]?.text;
if (t) {
  if (typeof t === "string") {
    try { parsed = JSON.parse(t); } catch(e) { parsed = $json; }
  } else if (typeof t === "object") {
    parsed = t;
  }
}

const stock = parsed?.stock || $json?.stock || "UNKNOWN";
const source = $('Merge1').first().json;
// Carry all financial fields forward from the original input
const financials = {
  current_price:        source?.current_price        ?? null,
  eps_current:          source?.eps_current          ?? null,
  bvps_current:         source?.bvps_current         ?? null,
  revenue_last_4q:      source?.revenue_last_4q      ?? null,
  net_income_last_4q:   source?.net_income_last_4q   ?? null,
  gross_margin_last_4q: source?.gross_margin_last_4q ?? null,
  total_debt_last_4q:   source?.total_debt_last_4q   ?? null,
  net_debt_latest:      source?.net_debt_latest      ?? null,
  net_cash_flag:        source?.net_cash_flag        ?? null,
  operating_margin_ttm: source?.operating_margin_ttm ?? null,
  fcf_ttm:              source?.fcf_ttm              ?? null,
  revenue_growth_yoy:   source?.revenue_growth_yoy   ?? null,
  f_score_data_ok:      source?.f_score_data_ok      ?? null,
  sector:               source?.sector               ?? null,
  seekingAlphaNewsText: source?.seekingAlphaNewsText ?? null,
};

return {
  json: {
    chatgpt_result: parsed,
    stock,
    ...financials
  }
};

let parsed = $json;
if ($json.output && typeof $json.output === "string") {
  try {
    const cleaned = $json.output.replace(/```json\n?|```/g, "").trim();
    parsed = JSON.parse(cleaned);
  } catch(e) { parsed = $json; }
} else if ($json.content?.parts?.[0]?.text) {
  try {
    parsed = JSON.parse($json.content.parts[0].text);
  } catch(e) { parsed = $json; }
}
if (parsed && parsed.gemini_result) parsed = parsed.gemini_result;

const stock = parsed?.stock || $json?.stock || "UNKNOWN";
const source = $('Merge1').first().json;
// Carry all financial fields forward from the original input
const financials = {
  current_price:        source?.current_price        ?? null,
  eps_current:          source?.eps_current          ?? null,
  bvps_current:         source?.bvps_current         ?? null,
  revenue_last_4q:      source?.revenue_last_4q      ?? null,
  net_income_last_4q:   source?.net_income_last_4q   ?? null,
  gross_margin_last_4q: source?.gross_margin_last_4q ?? null,
  total_debt_last_4q:   source?.total_debt_last_4q   ?? null,
  net_debt_latest:      source?.net_debt_latest      ?? null,
  net_cash_flag:        source?.net_cash_flag        ?? null,
  operating_margin_ttm: source?.operating_margin_ttm ?? null,
  fcf_ttm:              source?.fcf_ttm              ?? null,
  revenue_growth_yoy:   source?.revenue_growth_yoy   ?? null,
  f_score_data_ok:      source?.f_score_data_ok      ?? null,
  sector:               source?.sector               ?? null,
  seekingAlphaNewsText: source?.seekingAlphaNewsText ?? null,
};

return {
  json: {
    gemini_result: parsed,
    stock,
    ...financials
  }
};

const items_in = $input.all();
let chatgpt = null;
let gemini  = null;

for (const it of items_in) {
  const j = it.json || {};
  if (j.chatgpt_result) chatgpt = j.chatgpt_result;
  if (j.gemini_result)  gemini  = j.gemini_result;
}

if (!chatgpt || !gemini) {
  for (const it of items_in) {
    const j = it.json || {};
    if (!chatgpt && j.model === "CHATGPT") chatgpt = j;
    if (!gemini  && j.model === "GEMINI")  gemini  = j;
  }
}

// ── Pull financials from original source ──────────────────────────────
const source = $('Merge').first().json;

const stock         = chatgpt?.stock || gemini?.stock || source?.stock || "UNKNOWN";
