// Receives ALL accumulated done-branch items (one per processed stock)
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { summary_message: 'Report is done — no stocks analyzed.' } }];
}

const lines = items.map(item => {
  const j = item.json;
  const stock   = j.stock         || '?';
  const verdict = j.verdict || 'HOLD';
  const conf    = j.confidence    ? ` (${j.confidence}%)` : '';
  const price   = j.current_price ? ` $${Number(j.current_price).toFixed(2)}` : '';
  const target  = j.pt_base       ? ` → $${Number(j.pt_base).toFixed(2)}`     : '';
  const ma      = j.ma_signal && j.ma_signal !== 'MA_DATA_UNAVAILABLE'
                    ? ` [${j.ma_signal}]` : '';
  const icon = verdict === 'BUY'  ? '🟢'
             : verdict === 'SELL' ? '🔴'
             :                      '🟡';
   return `${icon} ${stock}: ${verdict}${conf}${ma}${price}${target}`;
});

const today = new Date().toISOString().split('T')[0];
const summary_message =
  `📊 *Screener Report — ${today}*\n\n`
  + lines.join('\n')
  + `\n\n${items.length} stock${items.length !== 1 ? 's' : ''} analyzed.`;

return [{ json: { summary_message } }];

// IDEA 2: Thesis Reversal Detection
// $json here is the analysis item (from If TRUE branch through Get Previous Verdict)
// We need to recover the analysis data and the prev verdict rows

// The item flowing through is the analysis item (passed as the first input into the lookup)
// After a Google Sheets lookup, the item might be the lookup result.
// We need to get the original item from before the lookup.

const analysisData = $('If').first().json;
const stock = analysisData.stock || '';

// Get all previous entries for this stock (from Get Previous Verdict lookup)
const prevRows = $input.all().filter(it => it.json.stock === stock && it.json.date);

// Sort by date descending and get the most recent
prevRows.sort((a, b) => (b.json.date || '').localeCompare(a.json.date || ''));

const prevEntry = prevRows.length > 0 ? prevRows[0].json : null;

function extractVerdict(rationale) {
  const r = (rationale || '').trim().toUpperCase();
  if (r.startsWith('BUY'))  return 'BUY';
  if (r.startsWith('SELL')) return 'SELL';
  return 'HOLD';
}

const prev_verdict = prevEntry ? (prevEntry.verdict || extractVerdict(prevEntry.rationale)) : null;
const prev_date    = prevEntry ? prevEntry.date : null;
const cur_rationale = analysisData.rationale || (analysisData.chatgpt_result || {}).rationale || '';
const cur_verdict = analysisData.verdict || extractVerdict(cur_rationale);


const thesis_reversal = prev_verdict !== null && prev_verdict !== cur_verdict;

return [{
  json: {
    ...analysisData,
    previous_verdict: prev_verdict,
    previous_date:    prev_date,
    thesis_reversal,
    thesis_reversal_msg: thesis_reversal
      ? `THESIS REVERSAL: ${stock}\n${prev_verdict} -> ${cur_verdict} (prev: ${prev_date})\nF:${analysisData.f_score ?? '?'}/9 | Confidence: ${analysisData.confidence ?? '?'}%\n${cur_rationale.slice(0, 200)}`
      : null
  }
}];

const all = $input.all();
const stocks = [];

const ALLOWED_SECTORS = [
  'Technology',
  'Healthcare',
  'Consumer Cyclical',
  'Financial Services',
  'Industrials',
  'Communication Services',
  'Consumer Defensive',
  'Energy',
  'Basic Materials',
  'Real Estate',
  'Utilities'
];

const MAX_PER_SECTOR = 4;   // sector diversity cap
const FINAL_LIMIT    = 20;  // max stocks to pass downstream

// ── Parse screener results ──────────────────────────────────────────────────
for (const item of all) {
  const j = item.json;
  if (!j.symbol || typeof j.symbol !== 'string') continue;

  const sector = j.sector || '';
  if (sector && !ALLOWED_SECTORS.includes(sector)) continue; // drop disallowed sectors

  stocks.push({
    stock:      j.symbol,
    company:    j.companyName  || '',
    market_cap: Number(j.marketCap          || 0),
    volume:     Number(j.volume             || 0),
    price:      Number(j.price              || 0),
    beta:       Number(j.beta               || 1),
    sector:     sector,
    exchange:   j.exchangeShortName         || '',
    scan_source: 'SCAN_STOCK'
  });
}

// ── Scoring function ─────────────────────────────────────────────────────────
// Max possible score = 7 points
//   Volume score  : 0–3 pts  (rewards healthy volume without mega-cap bias)
//   Cap score     : 0–2 pts  (sweet-spot $5B–$100B; penalises micro & mega)
//   Beta score    : 0–2 pts  (rewards 0.7–1.5; partial credit 0.5–0.7 / 1.5–2.0)

function scoreStock(s) {
  // Volume: 3 pts at 30M+, linear below
  const vol_score = Math.min(s.volume / 30_000_000, 1) * 3;

  // Market cap sweet spot: $5B–$100B = 2 pts; above $100B or below $5B = scaled down
  let cap_score = 0;
  const cap_b = s.market_cap / 1e9; // in billions
  if (cap_b >= 5 && cap_b <= 100) {
    cap_score = 2;
  } else if (cap_b > 100) {
    // Gradually reduce above $100B (still liquid but already well-covered)
    cap_score = Math.max(2 - (cap_b - 100) / 400, 0.5);
  } else if (cap_b >= 1) {
    // Below $5B but above $1B: partial credit
    cap_score = (cap_b / 5) * 1.5;
  }

  // Beta gradient: 0.7–1.5 ideal (2 pts), 0.5–0.7 or 1.5–2.0 partial (1 pt), else 0
  let beta_score = 0;
  if (s.beta >= 0.7 && s.beta <= 1.5) {
    beta_score = 2;
  } else if ((s.beta >= 0.5 && s.beta < 0.7) || (s.beta > 1.5 && s.beta <= 2.0)) {
    beta_score = 1;
  }

  return vol_score + cap_score + beta_score;
}

// ── Sort by score descending ─────────────────────────────────────────────────
stocks.sort((a, b) => scoreStock(b) - scoreStock(a));

// ── Apply sector diversity cap ───────────────────────────────────────────────
const sectorCount = {};
const selected    = [];

for (const s of stocks) {
  if (selected.length >= FINAL_LIMIT) break;

  const sec = s.sector || 'Unknown';
  const count = sectorCount[sec] || 0;

  if (count >= MAX_PER_SECTOR) continue; // skip if sector is full

  sectorCount[sec] = count + 1;
  selected.push(s);
}

// ── Return ───────────────────────────────────────────────────────────────────
return selected.map(item => ({ json: item }));

const j = $input.first().json;

const account_size = Number($vars?.ACCOUNT_SIZE || 20000);
const risk_pct = Number($vars?.RISK_PER_TRADE_PCT || 2) / 100;
const max_position_pct = 0.10;

const current_price = Number(j.current_price || 0);
const pt_bear = Number(j.pt_bear || 0);
const pt_base = Number(j.pt_base || 0);
const pt_bull = Number(j.pt_bull || 0);
const confidence = Number(j.confidence || 50);

// Only size for BUY signals with valid stop
if (current_price <= 0 || pt_bear <= 0 || pt_bear >= current_price || j.alert_verdict !== 'BUY') {
  return [{ json: {
    ...j,
    position_size_usd: null,
    shares_to_buy: null,
    stop_loss_price: pt_bear > 0 ? parseFloat(pt_bear.toFixed(2)) : null,
    risk_reward_ratio: null,
    kelly_position_usd: null,
    risk_note: j.alert_verdict !== 'BUY' ? 'Position sizing: N/A (not a BUY signal)' : 'Position sizing skipped: invalid stop level'
  }}];
}

const stop_distance = current_price - pt_bear;
const stop_distance_pct = stop_distance / current_price;
const risk_amount = account_size * risk_pct;

let raw_position_usd = risk_amount / stop_distance_pct;
const max_position_usd = account_size * max_position_pct;
const capped = raw_position_usd > max_position_usd;
const position_usd = Math.min(raw_position_usd, max_position_usd);

const shares_to_buy = Math.floor(position_usd / current_price);
if (shares_to_buy === 0) {
  return [{ json: {
    ...j,
    position_size_usd:  null,
    shares_to_buy:      0,
    stop_loss_price:    parseFloat(pt_bear.toFixed(2)),
    risk_reward_ratio:  null,
    kelly_position_usd: null,
    risk_note: `Stock price ($${current_price}) exceeds max position size ($${max_position_usd.toFixed(0)}) — increase account size or skip`
  }}];
}
const actual_cost = parseFloat((shares_to_buy * current_price).toFixed(2));
const actual_risk = parseFloat((shares_to_buy * stop_distance).toFixed(2));
const potential_reward = parseFloat((shares_to_buy * Math.max(pt_base - current_price, 0)).toFixed(2));
const rr = actual_risk > 0 ? parseFloat((potential_reward / actual_risk).toFixed(2)) : null;

// Kelly (quarter-Kelly for safety)
const p = confidence / 100;
const b = stop_distance > 0 ? (pt_bull - current_price) / stop_distance : 1;
const kelly_raw = p - (1 - p) / Math.max(b, 0.01);
const kelly_q = Math.max(0, kelly_raw * 0.25);
const kelly_usd = parseFloat((account_size * kelly_q).toFixed(2));

return [{ json: {
  ...j,
  account_size,
  risk_pct_label: (risk_pct * 100).toFixed(0) + '%',
  position_size_usd: actual_cost,
  shares_to_buy,
  stop_loss_price: parseFloat(pt_bear.toFixed(2)),
  stop_distance_pct: parseFloat((stop_distance_pct * 100).toFixed(1)),
  actual_risk_usd: actual_risk,
  potential_reward_usd: potential_reward,
  risk_reward_ratio: rr,
  kelly_position_usd: kelly_usd,
  position_capped: capped,
  risk_note: capped ? `Capped at 10% max ($${max_position_usd.toFixed(0)})` : `${(risk_pct*100).toFixed(0)}% risk rule`
}}];

