    };
  }
}

// ── Conviction label (matches consensus path) ─────────────────────────
function getConviction(gap) {
  if (gap < 10) return "HIGH";
  if (gap < 20) return "MEDIUM";
  return "LOW";
}

// ── Error fallback — now includes skip_row + enrichment fields ────────
if (!bull || !bear) {
  return [{
