if (upside >= 0.20 && f_score_ok)  final_verdict = "BUY";
else if (upside <= -0.15)          final_verdict = "SELL";
else                               final_verdict = "HOLD";

const rationale = `${final_verdict} (tiebreaker) — `
  + `Bull: ${bull.rationale} | Bear: ${bear.rationale}`;

return [{
  json: {
    stock,
    date:              today,
    verdict:           final_verdict,   // ← ADD THIS
    pt_bear:           true_bear,
    pt_base:           true_base,
    pt_bull:           true_bull,
    f_score,
    confidence:        Math.max(20, Math.min(90, avg_conf)),
    rationale,
    model:             "TIEBREAKER",
    current_price,                               // ← FIX: added
    row_key:           `${stock}_${today}_TIEBREAKER`,
    skip_row:          false,
    resolution_method: "TIEBREAKER",
    conviction:        getConviction(gap_pct),   // ← FIX: added
    gap_pct,                                     // ← FIX: added
    verdict_chatgpt,                             // ← FIX: added
    verdict_gemini                               // ← FIX: added
  }
}];

// ── CONSENSUS PATH — No Tiebreaker Needed ────────────────────────────
const needs_tiebreaker = $input.first().json?.needs_tiebreaker || false;
const gap_pct          = $input.first().json?.gap_pct          || 0;
const current_price    = $input.first().json?.current_price    || 0;
const verdict_chatgpt  = $input.first().json?.verdict_chatgpt  || null;
const verdict_gemini   = $input.first().json?.verdict_gemini   || null;

// ── Validate a candidate result ───────────────────────────────────────
function pickValid(x) {
  if (!x) return null;
  if (!x.stock) return null;
  const base = Number(x.pt_base);
  const bear = Number(x.pt_bear);
  const bull = Number(x.pt_bull);
  const conf = Number(x.confidence);
  if (!isFinite(base) || base <= 0) return null;
  if (!isFinite(bear) || bear <= 0) return null;
  if (!isFinite(bull) || bull <= 0) return null;
  if (!isFinite(conf) || conf <= 0) return null;
  return x;
}

// ── Conviction label ──────────────────────────────────────────────────
function getConviction(gap) {
  if (gap < 10) return "HIGH";
  if (gap < 20) return "MEDIUM";
  return "LOW";
}

// ── Collect and normalise candidates ─────────────────────────────────
const byStock = new Map();
const today   = new Date().toISOString().slice(0, 10);

for (const it of $input.all()) {
  const j = it.json || {};

  const candidates = [];

  if (j.chatgpt_result && typeof j.chatgpt_result === "object") {
    candidates.push({ ...j.chatgpt_result, model: j.chatgpt_result.model || "CHATGPT" });
  }
  if (j.gemini_result && typeof j.gemini_result === "object") {
    candidates.push({ ...j.gemini_result, model: j.gemini_result.model || "GEMINI" });
  }

  // Fallback: already flattened item
  if (candidates.length === 0 && j.stock && (j.pt_base || j.pt_bear || j.pt_bull)) {
    candidates.push({ ...j, model: j.model || "UNKNOWN" });
  }

  for (const cand of candidates) {
    const stock = cand.stock || j.stock || "";
    if (!stock) continue;

    const normalized = {
      stock,
      date:       cand.date       || null,
      pt_bear:    Number(cand.pt_bear    ?? NaN),
      pt_base:    Number(cand.pt_base    ?? NaN),
      pt_bull:    Number(cand.pt_bull    ?? NaN),
      f_score:    cand.f_score    ?? null,
      confidence: Number(cand.confidence ?? NaN),
      verdict:    cand.verdict    || null,
      rationale:  cand.rationale  || "",
      model:      cand.model      || "UNKNOWN"
    };

    const valid = pickValid(normalized);
    if (!valid) continue;

    if (!byStock.has(stock)) byStock.set(stock, []);
    byStock.get(stock).push(valid);
  }
}

// ── Build one consolidated output row per stock ───────────────────────
const out = [];

for (const [stock, arr] of byStock.entries()) {

  // Best result per model (highest confidence wins)
  const bestByModel = new Map();
  for (const r of arr) {
    const prev = bestByModel.get(r.model);
    if (!prev || (r.confidence ?? 0) > (prev.confidence ?? 0)) {
      bestByModel.set(r.model, r);
    }
  }

  const models = [...bestByModel.values()];

  // Average numeric fields across both models
  const avg = (fn) => models.reduce((s, r) => s + fn(r), 0) / models.length;

  // Use highest-confidence model for verdict, rationale, f_score, date
  const best = [...models].sort((a, b) => (b.confidence ?? 0) - (a.confidence ?? 0))[0];

  const date = best.date || today;

  out.push({
    json: {
      stock,
      date,
      pt_bear:           Number(avg(r => r.pt_bear).toFixed(2)),
      pt_base:           Number(avg(r => r.pt_base).toFixed(2)),
      pt_bull:           Number(avg(r => r.pt_bull).toFixed(2)),
      f_score:           best.f_score,
      confidence:        Math.max(20, Math.min(90, Math.round(avg(r => r.confidence)))),
      verdict:           best.verdict || verdict_chatgpt || verdict_gemini || null,
      rationale:         best.rationale || "No rationale provided",
      model:             "CONSENSUS",
      row_key:           `${stock}_${date}_CONSENSUS`,
      skip_row:          false,
      // ── Enrichment fields ────────────────────────────────────────
      resolution_method: "CONSENSUS",
      conviction:        getConviction(gap_pct),
      gap_pct,
      current_price,
      verdict_chatgpt,   // audit trail
      verdict_gemini     // audit trail
    }
  });
}

// ── Fallback if nothing valid came through ────────────────────────────
if (out.length === 0) {
  return [{
    json: {
      stock:             "",
      date:              today,
      pt_bear:           0,
      pt_base:           0,
      pt_bull:           0,
      f_score:           null,
      confidence:        0,
      verdict:           null,
      rationale:         "No valid analyst data",
      model:             "ERROR",
      row_key:           `ERROR_${today}`,
      skip_row:          true,
      resolution_method: "ERROR",
      conviction:        "NONE",
      gap_pct:           0,
      current_price:     0,
      verdict_chatgpt:   null,
      verdict_gemini:    null
    }
  }];
}

return out;

const priceResp    = $('Consolidate price history').first().json;
const alertData    = $('Alert Filter').first().json;
const earningsResp = $input.all().map(item => item.json);


// ── Price History ─────────────────────────────────────────────────────
const closes = (priceResp?.historical || [])
  .map(p => Number(p.close))
  .filter(v => !isNaN(v));

// ── SMA ───────────────────────────────────────────────────────────────
function sma(arr, period) {
  if (arr.length < period) return null;
  return arr.slice(0, period).reduce((a, b) => a + b, 0) / period;
}

const ma_50  = sma(closes, 50);
const ma_200 = sma(closes, 200);

// ── RSI-14 ────────────────────────────────────────────────────────────
function rsi(arr, period = 14) {
  if (arr.length < period + 1) return null;
  const c = [...arr].reverse(); // oldest first for calculation
  let gains = 0, losses = 0;
  for (let i = c.length - period; i < c.length; i++) {
    const diff = c[i] - c[i - 1];
    if (diff >= 0) gains  += diff;
    else           losses -= diff;
  }
  const avgGain = gains  / period;
  const avgLoss = losses / period;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return Number((100 - 100 / (1 + rs)).toFixed(1));
}

const rsi_14 = rsi(closes, 14);

// ── RSI Signal ────────────────────────────────────────────────────────
let rsi_signal = 'UNKNOWN';
if (rsi_14 !== null) {
  if      (rsi_14 <= 35) rsi_signal = 'OVERSOLD';
  else if (rsi_14 <= 55) rsi_signal = 'NEUTRAL';
  else if (rsi_14 <= 70) rsi_signal = 'ELEVATED';
  else                   rsi_signal = 'OVERBOUGHT';
}

// ── MA Check ──────────────────────────────────────────────────────────
const current_price = Number(alertData.current_price || 0);
const ma_50_passed  = ma_50 !== null && current_price > 0 && current_price >= ma_50;

let trend_tier = 'UNKNOWN';
if (ma_200 !== null && ma_50 !== null && current_price > 0) {
  if      (current_price > ma_200 && current_price > ma_50)  trend_tier = 'STRONG_UPTREND';
  else if (current_price > ma_200 && current_price <= ma_50) trend_tier = 'PULLBACK';
  else                                                        trend_tier = 'DOWNTREND';
} else if (ma_50 !== null && current_price > 0) {
  trend_tier = ma_50_passed ? 'ABOVE_50MA' : 'BELOW_50MA';
}

// ── Earnings ──────────────────────────────────────────────────────────
let next_earnings_date = null;
let days_to_earnings   = null;
let earnings_warning   = null;
try {
  if (Array.isArray(earningsResp) && earningsResp.length > 0) {
    const now = Date.now();
    const upcoming = earningsResp
      .filter(e => e.date)
      .map(e => ({ date: e.date, ms: new Date(e.date).getTime() }))
      .filter(e => Number.isFinite(e.ms) && e.ms > now)
      .sort((a, b) => a.ms - b.ms);
    if (upcoming.length > 0) {
      next_earnings_date = upcoming[0].date;
      days_to_earnings   = Math.ceil((upcoming[0].ms - now) / (1000 * 60 * 60 * 24));
      if (days_to_earnings <= 14)
        earnings_warning = `EARNINGS IN ${days_to_earnings} DAYS (${next_earnings_date}) — binary risk`;
    }
  }
} catch(e) {}

// ── Output ────────────────────────────────────────────────────────────
return [{ json: {
  ...alertData,
  ma_50:             ma_50  !== null ? Number(ma_50.toFixed(2))  : null,
  ma_200:            ma_200 !== null ? Number(ma_200.toFixed(2)) : null,
  rsi_14,
  ma_check_passed:   ma_50 === null ? true : ma_50_passed,
  ma_signal:         ma_50 === null ? 'MA_DATA_UNAVAILABLE' : (ma_50_passed ? 'ABOVE_50MA' : 'BELOW_50MA'),
  trend_tier,
  rsi_signal,
  next_earnings_date,
  days_to_earnings,
  earnings_warning
}}];

